import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";
import Modal from "../components/Modal";
import {
  fetchCoursesRequest,
  fetchCoursesSuccess,
  fetchCoursesFailure,
  filterCoursesByClass,
  deleteCourse,
} from "../courseReducer";

function Courses() {
  const { filteredCourses = [], courses = [], loading, error } = useSelector((state) => state.courses || {});
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [courseToDelete, setCourseToDelete] = useState(null);

  useEffect(() => {
    const fetchCourses = async () => {
      dispatch(fetchCoursesRequest());
      try {
        const response = await fetch("http://localhost:3001/courses");
        if (!response.ok) throw new Error("Не удалось загрузить курсы");
        const data = await response.json();
        if (!Array.isArray(data)) throw new Error("Некорректные данные курсов");
        const uniqueCourses = Array.from(
          new Map(data.map((course) => [course.id, course])).values()
        );
        console.log("Fetched courses:", uniqueCourses);
        dispatch(fetchCoursesSuccess(uniqueCourses));
        if (user?.role === "student") {
          dispatch(filterCoursesByClass(user.classId));
        }
      } catch (error) {
        console.error("Error fetching courses:", error);
        dispatch(fetchCoursesFailure(error.message));
        toast.error(error.message || "Ошибка загрузки курсов");
      }
    };
    fetchCourses();
  }, [dispatch, user]);

  useEffect(() => {
    if (user?.role === "student") {
      dispatch(filterCoursesByClass(user.classId));
    }
  }, [dispatch, user, courses]);

  function openDeleteModal(courseId) {
    console.log("Opening delete modal for course ID:", courseId);
    setCourseToDelete(courseId);
    setIsModalOpen(true);
  }

  async function handleDelete() {
    console.log("Attempting to delete course with ID:", courseToDelete);
    try {
      const response = await fetch(`http://localhost:3001/courses/${courseToDelete}`, {
        method: "DELETE",
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(errorText || "Не удалось удалить курс");
      }

      dispatch(deleteCourse(parseInt(courseToDelete)));
      toast.success("Курс успешно удален!");
    } catch (error) {
      console.error("Delete error:", error);
      toast.error(error.message || "Сетевая ошибка при удалении курса");
    } finally {
      setIsModalOpen(false);
      setCourseToDelete(null);
    }
  }

  if (loading) return <div className="container mt-5">Загрузка...</div>;
  if (error) return <div className="container mt-5">Ошибка: {error}</div>;
  if (!filteredCourses.length) return <div className="container mt-5">Курсы не найдены</div>;

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Доступные курсы</h1>
      {user?.role === "teacher" && (
        <div className="mb-4">
          <Link to="/add-course" className="btn btn-success">
            Добавить курс
          </Link>
        </div>
      )}
      <ul className="list-group">
        {filteredCourses.map((course) => (
          <li
            key={course.id}
            className="list-group-item d-flex justify-content-between align-items-center"
          >
            <span>{course.name}</span>
            {user?.role === "teacher" &&
              parseInt(course.teacherId) === parseInt(user.id) && (
                <div>
                  <Link
                    to={`/edit-course/${course.id}`}
                    className="btn btn-warning btn-sm me-2"
                  >
                    Редактировать
                  </Link>
                  <button
                    onClick={() => openDeleteModal(course.id)}
                    className="btn btn-danger btn-sm"
                  >
                    Удалить
                  </button>
                </div>
              )}
          </li>
        ))}
      </ul>
      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false);
          setCourseToDelete(null);
        }}
        onConfirm={handleDelete}
        message="Вы уверены, что хотите удалить этот курс?"
      />
    </div>
  );
}

export default Courses;
